import{_ as i,o as s,c as a,a2 as l}from"./chunks/framework.CGYl2SZ_.js";const n=JSON.parse('{"title":"signal","description":"signal 页面","frontmatter":{"title":"signal","description":"signal 页面"},"headers":[],"relativePath":"channels/signal.md","filePath":"channels/signal.md"}');const e=i({name:"channels/signal.md"},[["render",function(i,n,e,t,h,p){return s(),a("div",null,[...n[0]||(n[0]=[l('<h1 id="signal" tabindex="-1">Signal <a class="header-anchor" href="#signal" aria-label="Permalink to &quot;Signal&quot;">​</a></h1><h1 id="signal-signal-cli" tabindex="-1">Signal（signal-cli） <a class="header-anchor" href="#signal-signal-cli" aria-label="Permalink to &quot;Signal（signal-cli）&quot;">​</a></h1><p>状态：外部 CLI 集成。网关通过 HTTP JSON-RPC + SSE 与 <code>signal-cli</code> 通信。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>OpenClaw 安装在您的服务器上（下面的 Linux 流程在 Ubuntu 24 上测试）。</li><li><code>signal-cli</code> 可用在网关运行的主机上。</li><li>一个可以接收一条验证 SMS 的电话号码（用于 SMS 注册路径）。</li><li>注册期间需要浏览器访问 Signal captcha（<code>signalcaptchas.org</code>）。</li></ul><h2 id="快速设置-入门" tabindex="-1">快速设置（入门） <a class="header-anchor" href="#快速设置-入门" aria-label="Permalink to &quot;快速设置（入门）&quot;">​</a></h2><ol><li><strong>为机器人使用单独的电话号码</strong>（推荐）。</li><li>在主机上安装 <code>signal-cli</code>（如果使用 JVM 构建，则需要 Java）。</li><li>选择一个设置路径： <ul><li><strong>路径 A（QR 链接）：</strong> <code>signal-cli link -n &quot;OpenClaw&quot;</code> 然后用 Signal 扫描。</li><li><strong>路径 B（SMS 注册）：</strong> 使用 captcha + SMS 验证注册专用号码。</li></ul></li><li>配置 OpenClaw 并重启网关。</li><li>发送第一条私信并批准配对（<code>openclaw pairing approve signal &lt;CODE&gt;</code>）。</li></ol><p>最小配置：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    signal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      account</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15551234567&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      cliPath</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;signal-cli&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      allowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15557654321&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>字段参考：</p><table tabindex="0"><thead><tr><th>字段</th><th>描述</th></tr></thead><tbody><tr><td><code>account</code></td><td>机器人电话号码，E.164 格式（<code>+15551234567</code>）</td></tr><tr><td><code>cliPath</code></td><td><code>signal-cli</code> 的路径（如果在 PATH 中则使用 <code>signal-cli</code>）</td></tr><tr><td><code>dmPolicy</code></td><td>私信访问策略（推荐 <code>pairing</code>）</td></tr><tr><td><code>allowFrom</code></td><td>允许私信的电话号码或 <code>uuid:&lt;id&gt;</code> 值</td></tr></tbody></table><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><ul><li>通过 <code>signal-cli</code> 的 Signal 渠道（不是嵌入的 libsignal）。</li><li>确定性路由：回复始终返回 Signal。</li><li>私信共享代理的主会话；群组隔离（<code>agent:&lt;agentId&gt;:signal:group:&lt;groupId&gt;</code>）。</li></ul><h2 id="配置写入" tabindex="-1">配置写入 <a class="header-anchor" href="#配置写入" aria-label="Permalink to &quot;配置写入&quot;">​</a></h2><p>默认情况下，允许 Signal 写入由 <code>/config set|unset</code> 触发的配置更新（需要 <code>commands.config: true</code>）。</p><p>禁用：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">signal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">configWrites</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="号码模型-重要" tabindex="-1">号码模型（重要） <a class="header-anchor" href="#号码模型-重要" aria-label="Permalink to &quot;号码模型（重要）&quot;">​</a></h2><ul><li>网关连接到一个 <strong>Signal 设备</strong>（<code>signal-cli</code> 账户）。</li><li>如果您在 <strong>您的个人 Signal 账户</strong>上运行机器人，它将忽略您自己的消息（循环保护）。</li><li>对于&quot;我发短信给机器人，它回复&quot;，使用<strong>单独的机器人号码</strong>。</li></ul><h2 id="设置路径-a-链接现有-signal-账户-qr" tabindex="-1">设置路径 A：链接现有 Signal 账户（QR） <a class="header-anchor" href="#设置路径-a-链接现有-signal-账户-qr" aria-label="Permalink to &quot;设置路径 A：链接现有 Signal 账户（QR）&quot;">​</a></h2><ol><li>安装 <code>signal-cli</code>（JVM 或本机构建）。</li><li>链接机器人账户： <ul><li><code>signal-cli link -n &quot;OpenClaw&quot;</code> 然后在 Signal 中扫描 QR。</li></ul></li><li>配置 Signal 并启动网关。</li></ol><p>示例：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    signal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      account</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15551234567&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      cliPath</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;signal-cli&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      allowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15557654321&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>多账户支持：使用 <code>channels.signal.accounts</code> 和每账户配置及可选 <code>name</code>。参见 <a href="/gateway/configuration.html#telegramaccounts--discordaccounts--slackaccounts--signalaccounts--imessageaccounts"><code>gateway/configuration</code></a> 了解共享模式。</p><h2 id="设置路径-b-注册专用机器人号码-sms-linux" tabindex="-1">设置路径 B：注册专用机器人号码（SMS，Linux） <a class="header-anchor" href="#设置路径-b-注册专用机器人号码-sms-linux" aria-label="Permalink to &quot;设置路径 B：注册专用机器人号码（SMS，Linux）&quot;">​</a></h2><p>当您想要专用机器人号码而不是链接现有 Signal 应用账户时使用此选项。</p><ol><li>获取一个可以接收 SMS 的号码（または语音验证用于座机）。 <ul><li>使用专用机器人号码以避免账户/会话冲突。</li></ul></li><li>在网关主机上安装 <code>signal-cli</code>：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VERSION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %{url_effective}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/AsamK/signal-cli/releases/latest</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s/^.*\\/v//&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://github.com/AsamK/signal-cli/releases/download/v${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VERSION</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}/signal-cli-${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VERSION</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}-Linux-native.tar.gz&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;signal-cli-${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VERSION</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}-Linux-native.tar.gz&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/signal-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">signal-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果您使用 JVM 构建（<code>signal-cli-${VERSION}.tar.gz</code>），首先安装 JRE 25+。 保持 <code>signal-cli</code> 更新；上游指出随着 Signal 服务器 API 的变化，旧版本可能会中断。</p><ol start="3"><li>注册并验证号码：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">signal-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BOT_PHONE_NUMBE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">R</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> register</span></span></code></pre></div><p>如果需要 captcha：</p><ol><li>打开 <code>https://signalcaptchas.org/registration/generate.html</code>。</li><li>完成 captcha，从&quot;Open Signal&quot;复制 <code>signalcaptcha://...</code> 链接目标。</li><li>尽可能从与浏览器会话相同的外部 IP 运行。</li><li>立即再次运行注册（captcha 令牌很快过期）：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">signal-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BOT_PHONE_NUMBE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">R</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> register</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --captcha</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;SIGNALCAPTCHA_URL&gt;&#39;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">signal-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BOT_PHONE_NUMBE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">R</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">VERIFICATION_COD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><ol start="5"><li>配置 OpenClaw，重启网关，验证渠道：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果您将网关作为用户 systemd 服务运行：</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw-gateway</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 然后验证：</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --probe</span></span></code></pre></div><ol start="6"><li>配对您的私信发送者： <ul><li>向机器人号码发送任何消息。</li><li>在服务器上批准代码：<code>openclaw pairing approve signal &lt;PAIRING_CODE&gt;</code>。</li><li>在您的手机上将机器人号码保存为联系人以避免&quot;未知联系人&quot;。</li></ul></li></ol><p>重要：使用 <code>signal-cli</code> 注册电话号码可能会使该号码的主要 Signal 应用会话取消身份验证。首选专用机器人号码，或者如果您需要保持现有手机应用设置，请使用 QR 链接模式。</p><p>上游参考：</p><ul><li><code>signal-cli</code> README：<code>https://github.com/AsamK/signal-cli</code></li><li>Captcha 流程：<code>https://github.com/AsamK/signal-cli/wiki/Registration-with-captcha</code></li><li>链接流程：<code>https://github.com/AsamK/signal-cli/wiki/Linking-other-devices-(Provisioning)</code></li></ul><h2 id="外部守护进程模式-httpurl" tabindex="-1">外部守护进程模式（httpUrl） <a class="header-anchor" href="#外部守护进程模式-httpurl" aria-label="Permalink to &quot;外部守护进程模式（httpUrl）&quot;">​</a></h2><p>如果您想自己管理 <code>signal-cli</code>（慢速 JVM 冷启动、容器初始化或共享 CPU），请单独运行守护进程并指向 OpenClaw：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    signal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      httpUrl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:8080&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      autoStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>这跳过自动生成和 OpenClaw 内的启动等待。对于自动生成时的慢速启动，设置 <code>channels.signal.startupTimeoutMs</code>。</p><h2 id="访问控制-私信-群组" tabindex="-1">访问控制（私信 + 群组） <a class="header-anchor" href="#访问控制-私信-群组" aria-label="Permalink to &quot;访问控制（私信 + 群组）&quot;">​</a></h2><p>私信：</p><ul><li>默认：<code>channels.signal.dmPolicy = &quot;pairing&quot;</code>。</li><li>未知发送者收到配对代码；消息在被批准之前被忽略（代码在 1 小时后过期）。</li><li>批准方式： <ul><li><code>openclaw pairing list signal</code></li><li><code>openclaw pairing approve signal &lt;CODE&gt;</code></li></ul></li><li>配对是 Signal 私信的默认令牌交换。详情：<a href="/channels/pairing.html">配对</a></li><li>来自 <code>sourceUuid</code> 的仅 UUID 发送者存储为 <code>uuid:&lt;id&gt;</code> 在 <code>channels.signal.allowFrom</code> 中。</li></ul><p>群组：</p><ul><li><code>channels.signal.groupPolicy = open | allowlist | disabled</code>。</li><li><code>channels.signal.groupAllowFrom</code> 控制谁可以在群组中触发当 <code>allowlist</code> 时。</li><li><code>channels.signal.groups[&quot;&lt;group-id&gt;&quot; | &quot;*&quot;]</code> 可以用 <code>requireMention</code>、<code>tools</code> 和 <code>toolsBySender</code> 覆盖群组行为。</li><li>在多账户设置中使用 <code>channels.signal.accounts.&lt;id&gt;.groups</code> 进行每账户覆盖。</li><li>运行时注意：如果完全缺少 <code>channels.signal</code>，运行时回退到 <code>groupPolicy=&quot;allowlist&quot;</code> 进行群组检查（即使设置了 <code>channels.defaults.groupPolicy</code>）。</li></ul><h2 id="工作原理-行为" tabindex="-1">工作原理（行为） <a class="header-anchor" href="#工作原理-行为" aria-label="Permalink to &quot;工作原理（行为）&quot;">​</a></h2><ul><li><code>signal-cli</code> 作为守护进程运行；网关通过 SSE 读取事件。</li><li>入站消息规范化到共享渠道信封中。</li><li>回复始终路由回同一号码或群组。</li></ul><h2 id="媒体和限制" tabindex="-1">媒体和限制 <a class="header-anchor" href="#媒体和限制" aria-label="Permalink to &quot;媒体和限制&quot;">​</a></h2><ul><li>出站文本分块到 <code>channels.signal.textChunkLimit</code>（默认 4000）。</li><li>可选换行分块：设置 <code>channels.signal.chunkMode=&quot;newline&quot;</code> 在长度分块之前按空行（段落边界）拆分。</li><li>支持附件（从 <code>signal-cli</code> 获取 base64）。</li><li>默认媒体上限：<code>channels.signal.mediaMaxMb</code>（默认 8）。</li><li>使用 <code>channels.signal.ignoreAttachments</code> 跳过下载媒体。</li><li>群组历史上下文使用 <code>channels.signal.historyLimit</code>（或 <code>channels.signal.accounts.*.historyLimit</code>），回退到 <code>messages.groupChat.historyLimit</code>。设置为 <code>0</code> 禁用（默认 50）。</li></ul><h2 id="打字和已读回执" tabindex="-1">打字和已读回执 <a class="header-anchor" href="#打字和已读回执" aria-label="Permalink to &quot;打字和已读回执&quot;">​</a></h2><ul><li><strong>打字指示符</strong>：OpenClaw 通过 <code>signal-cli sendTyping</code> 发送打字信号并在回复运行时刷新它们。</li><li><strong>已读回执</strong>：当 <code>channels.signal.sendReadReceipts</code> 为真时，OpenClaw 为允许的私信转发已读回执。</li><li>Signal-cli 不公开群组的已读回执。</li></ul><h2 id="反应-消息工具" tabindex="-1">反应（消息工具） <a class="header-anchor" href="#反应-消息工具" aria-label="Permalink to &quot;反应（消息工具）&quot;">​</a></h2><ul><li>使用 <code>message action=react</code> 与 <code>channel=signal</code>。</li><li>目标：发送者 E.164 或 UUID（使用配对输出的 <code>uuid:&lt;id&gt;</code>；裸 UUID 也可以）。</li><li><code>messageId</code> 是您正在反应的 messageId（Signal 时间戳）。</li><li>群组反应需要 <code>targetAuthor</code> 或 <code>targetAuthorUuid</code>。</li></ul><p>示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>message action=react channel=signal target=uuid:123e4567-e89b-12d3-a456-426614174000 messageId=1737630212345 emoji=🔥</span></span>\n<span class="line"><span>message action=react channel=signal target=+15551234567 messageId=1737630212345 emoji=🔥 remove=true</span></span>\n<span class="line"><span>message action=react channel=signal target=signal:group:&lt;groupId&gt; targetAuthor=uuid:&lt;sender-uuid&gt; messageId=1737630212345 emoji=✅</span></span></code></pre></div><p>配置：</p><ul><li><code>channels.signal.actions.reactions</code>：启用/禁用反应操作（默认 true）。</li><li><code>channels.signal.reactionLevel</code>：<code>off | ack | minimal | extensive</code>。 <ul><li><code>off</code>/<code>ack</code> 禁用代理反应（消息工具 <code>react</code> 会报错）。</li><li><code>minimal</code>/<code>extensive</code> 启用代理反应并设置指导级别。</li></ul></li><li>每账户覆盖：<code>channels.signal.accounts.&lt;id&gt;.actions.reactions</code>、<code>channels.signal.accounts.&lt;id&gt;.reactionLevel</code>。</li></ul><h2 id="投递目标-cli-cron" tabindex="-1">投递目标（CLI/cron） <a class="header-anchor" href="#投递目标-cli-cron" aria-label="Permalink to &quot;投递目标（CLI/cron）&quot;">​</a></h2><ul><li>私信：<code>signal:+15551234567</code>（或纯 E.164）。</li><li>UUID 私信：<code>uuid:&lt;id&gt;</code>（或裸 UUID）。</li><li>群组：<code>signal:group:&lt;groupId&gt;</code>。</li><li>用户名：<code>username:&lt;name&gt;</code>（如果您的 Signal 账户支持）。</li></ul><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><p>首先运行这个：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --probe</span></span></code></pre></div><p>然后如需要确认私信配对状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> signal</span></span></code></pre></div><p>常见失败：</p><ul><li>守护进程可到达但无回复：验证账户/守护进程设置（<code>httpUrl</code>、<code>account</code>）和接收模式。</li><li>私信被忽略：发送者待配对批准。</li><li>群组消息被忽略：群组发送者/提及门控阻止投递。</li><li>编辑后配置验证错误：运行 <code>openclaw doctor --fix</code>。</li><li>诊断中缺少 Signal：确认 <code>channels.signal.enabled: true</code>。</li></ul><p>额外检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> signal</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pgrep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -af</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> signal-cli</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;signal&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/tmp/openclaw/openclaw-$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%Y-%m-%d).log&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span></code></pre></div><p>分类流程：<a href="/channels/troubleshooting.html">/channels/troubleshooting</a></p><h2 id="安全说明" tabindex="-1">安全说明 <a class="header-anchor" href="#安全说明" aria-label="Permalink to &quot;安全说明&quot;">​</a></h2><ul><li><code>signal-cli</code> 在本地存储账户密钥（通常在 <code>~/.local/share/signal-cli/data/</code>）。</li><li>在服务器迁移或重建之前备份 Signal 账户状态。</li><li>除非您明确想要更广泛的私信访问，否则保持 <code>channels.signal.dmPolicy: &quot;pairing&quot;</code>。</li><li>SMS 验证仅在注册或恢复流程中需要，但失去对号码/账户的控制可能会使重新注册复杂化。</li></ul><h2 id="配置参考-signal" tabindex="-1">配置参考（Signal） <a class="header-anchor" href="#配置参考-signal" aria-label="Permalink to &quot;配置参考（Signal）&quot;">​</a></h2><p>完整配置：<a href="/gateway/configuration.html">配置</a></p><p>提供商选项：</p><ul><li><code>channels.signal.enabled</code>：启用/禁用渠道启动。</li><li><code>channels.signal.account</code>：机器人账户的 E.164。</li><li><code>channels.signal.cliPath</code>：<code>signal-cli</code> 的路径。</li><li><code>channels.signal.httpUrl</code>：完整守护进程 URL（覆盖主机/端口）。</li><li><code>channels.signal.httpHost</code>、<code>channels.signal.httpPort</code>：守护进程绑定（默认 127.0.0.1:8080）。</li><li><code>channels.signal.autoStart</code>：自动生成守护进程（默认 true 如果 <code>httpUrl</code> 未设置）。</li><li><code>channels.signal.startupTimeoutMs</code>：启动等待超时（毫秒）（上限 120000）。</li><li><code>channels.signal.receiveMode</code>：<code>on-start | manual</code>。</li><li><code>channels.signal.ignoreAttachments</code>：跳过附件下载。</li><li><code>channels.signal.ignoreStories</code>：忽略守护进程的故事。</li><li><code>channels.signal.sendReadReceipts</code>：转发已读回执。</li><li><code>channels.signal.dmPolicy</code>：<code>pairing | allowlist | open | disabled</code>（默认：pairing）。</li><li><code>channels.signal.allowFrom</code>：私信白名单（E.164 或 <code>uuid:&lt;id&gt;</code>）。<code>open</code> 需要 <code>&quot;*&quot;</code>。Signal 没有用户名；使用电话/UUID id。</li><li><code>channels.signal.groupPolicy</code>：<code>open | allowlist | disabled</code>（默认：allowlist）。</li><li><code>channels.signal.groupAllowFrom</code>：群组发送者白名单。</li><li><code>channels.signal.groups</code>：按群组覆盖，按 Signal 群组 ID 键控（或 <code>&quot;*&quot;</code>）。支持字段：<code>requireMention</code>、<code>tools</code>、<code>toolsBySender</code>。</li><li><code>channels.signal.accounts.&lt;id&gt;.groups</code>：多账户设置的每账户版本 <code>channels.signal.groups</code>。</li><li><code>channels.signal.historyLimit</code>：作为上下文包含的最大群组消息数（0 禁用）。</li><li><code>channels.signal.dmHistoryLimit</code>：私信历史限制（用户轮次）。每用户覆盖：<code>channels.signal.dms[&quot;&lt;phone_or_uuid&gt;&quot;].historyLimit</code>。</li><li><code>channels.signal.textChunkLimit</code>：出站块大小（字符）。</li><li><code>channels.signal.chunkMode</code>：<code>length</code>（默认）或 <code>newline</code> 在长度分块之前按空行（段落边界）拆分。</li><li><code>channels.signal.mediaMaxMb</code>：入站/出站媒体上限（MB）。</li></ul><p>相关全局选项：</p><ul><li><code>agents.list[].groupChat.mentionPatterns</code>（Signal 不支持原生提及）。</li><li><code>messages.groupChat.mentionPatterns</code>（全局回退）。</li><li><code>messages.responsePrefix</code>。</li></ul>',81)])])}]]);export{n as __pageData,e as default};
